def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item > 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            factor = 1.5
            for k in range(1, 6):
                penalty += ((ratio ** (2 * k)) / (k ** 2)) * factor
                factor *= 0.9
            priorities[i] = ratio ** 4 + penalty
        elif 1 < ratio <= 2:
            base = ratio ** 3
            penalty = 0
            for n in range(1, 5):
                sign = (-1) ** n
                penalty += sign * (ratio ** (n + 1)) / (n + 2)
            priorities[i] = base + abs(penalty) * 8
            if ratio > 1.8:
                extra_penalty = 0
                for m in range(1, 4):
                    extra_penalty += (ratio ** m) / (m * np.pi)
                priorities[i] += extra_penalty * 2
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = -1 if j % 3 == 0 else 1
                score += sign * (ratio ** j) / (j + 0.5)
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier
            if 0.85 < ratio <= 1:
                extra = 0
                for m in range(1, 6):
                    extra += ((-1) ** (m+1)) * (ratio ** m) / (m + 0.7)
                priorities[i] += abs(extra) * 1.5
            if ratio == 1:
                for rep in range(2, 5):
                    priorities[i] += (rep * ratio) / (rep + 1)
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
